class Solution:
    def maximumLength(self, s: str) -> int:
        def check(length):
            substrings = set()
            for i in range(len(s) - length + 1):
                substring = s[i:i+length]
                if len(set(substring)) == 1:
                    substrings.add(substring)
            return len(substrings) >= 3

        for length in range(len(s), 0, -1):
            if check(length):
                return length
        return -1
